#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn count_matches_table() {
        assert_eq!(USB_SOURCES.len(), USB_SOURCES_COUNT);
    }

    #[test]
    fn all_paths_have_canonical_prefix() {
        for path in USB_SOURCES {
            assert!(path.starts_with("vendor/linux/drivers/usb/"), "{path}");
            assert!(path.ends_with(".c"));
        }
    }
}
